import React, { useContext } from 'react';
import { Container, Row, Col } from 'react-bootstrap';
// Asumimos que SettingsContext ya está disponible
import { SettingsContext } from '../context/SettingsContext'; 

const Footer = () => {
  const { settings } = useContext(SettingsContext);
  const siteName = settings?.siteName || 'Tecnotitlan';
  const currentYear = new Date().getFullYear();

  return (
    // CRÍTICO: Fondo oscuro (--brand-dark) y pt-5 pb-3 para espaciado.
    // mt-auto es necesario para forzar el footer hacia abajo si el main no llena la pantalla.
    <footer 
      style={{ backgroundColor: 'var(--brand-dark)' }} 
      className="text-white pt-5 pb-3 mt-auto shadow-inner"
    >
      <Container>
        <Row className="mb-4">
          
          {/* Columna 1: Info de la Marca */}
          <Col md={4} className="mb-4 mb-md-0">
            <h5 className="font-bold text-lg text-white mb-3">{siteName}</h5>
            <p className="text-gray-400 text-sm">
              Tecnología con Raíces, Poder sin Límites.
            </p>
            {/* Redes sociales */}
            <div className="mt-3 flex gap-3">
                <i className="fab fa-facebook-f text-lg text-gray-500 hover:text-white transition-colors cursor-pointer"></i>
                <i className="fab fa-instagram text-lg text-gray-500 hover:text-white transition-colors cursor-pointer"></i>
                <i className="fab fa-whatsapp text-lg text-gray-500 hover:text-white transition-colors cursor-pointer"></i>
            </div>
          </Col>

          {/* Columna 2: Navegación */}
          <Col xs={6} md={2} className="mb-4 mb-md-0">
            <h5 className="font-bold text-white mb-3">Navegación</h5>
            <ul className="list-unstyled text-sm flex flex-col gap-2">
              <li><a href="/" className="text-gray-400 hover:text-white no-underline transition-colors">Inicio</a></li>
              <li><a href="/cart" className="text-gray-400 hover:text-white no-underline transition-colors">Carrito</a></li>
              <li><a href="/profile" className="text-gray-400 hover:text-white no-underline transition-colors">Perfil</a></li>
            </ul>
          </Col>

          {/* Columna 3: Legal */}
          <Col xs={6} md={3} className="mb-4 mb-md-0">
            <h5 className="font-bold text-white mb-3">Legal</h5>
            <ul className="list-unstyled text-sm flex flex-col gap-2">
              <li><a href="#privacy" className="text-gray-400 hover:text-white no-underline transition-colors">Política de Privacidad</a></li>
              <li><a href="#terms" className="text-gray-400 hover:text-white no-underline transition-colors">Términos de Servicio</a></li>
            </ul>
          </Col>

          {/* Columna 4: Pagos (Íconos de tarjetas) */}
          <Col md={3}>
            <h5 className="font-bold text-white mb-3">Pagos Seguros</h5>
            <div className="flex flex-wrap gap-2 text-3xl">
                <i className="fab fa-cc-paypal text-gray-400"></i>
                <i className="fab fa-cc-mastercard text-gray-400"></i>
                <i className="fab fa-cc-visa text-gray-400"></i>
                <i className="fab fa-cc-amex text-gray-400"></i>
            </div>
          </Col>
        </Row>
        
        {/* Sección de Copyright */}
        <Row className="border-t border-gray-800 pt-3">
          <Col className="text-center text-sm text-gray-500">
            &copy; {currentYear} {siteName}. Todos los derechos reservados. Desarrollado con el poder del Cóndor.
          </Col>
        </Row>
      </Container>
    </footer>
  );
};

export default Footer;
